void deposit_worker(SecureBank& bank, const std::string& account_id, int num_transactions) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()));
    std::uniform_real_distribution<double> amount_dist(10.0, 500.0);

    for (int i = 0; i < num_transactions; ++i) {
        double amount = std::round(amount_dist(rng) * 100.0) / 100.0;
        bank.deposit(account_id, amount);
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }
}

void withdraw_worker(SecureBank& bank, const std::string& account_id, int num_transactions) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()));
    std::uniform_real_distribution<double> amount_dist(5.0, 100.0);

    for (int i = 0; i < num_transactions; ++i) {
        double amount = std::round(amount_dist(rng) * 100.0) / 100.0;
        bank.withdraw(account_id, amount);
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }
}

void transfer_worker(SecureBank& bank, const std::vector<std::string>& account_ids, int num_transactions) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()));
    std::uniform_real_distribution<double> amount_dist(10.0, 200.0);
    std::uniform_int_distribution<size_t> acct_dist(0, account_ids.size() - 1);

    for (int i = 0; i < num_transactions; ++i) {
        size_t from_idx = acct_dist(rng);
        size_t to_idx = acct_dist(rng);
        while (to_idx == from_idx) {
            to_idx = acct_dist(rng);
        }

        double amount = std::round(amount_dist(rng) * 100.0) / 100.0;
        bank.transfer(account_ids[from_idx], account_ids[to_idx], amount);
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }
}

void balance_reader(SecureBank& bank, const std::vector<std::string>& account_ids, int num_reads) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()));
    std::uniform_int_distribution<size_t> acct_dist(0, account_ids.size() - 1);

    for (int i = 0; i < num_reads; ++i) {
        size_t idx = acct_dist(rng);
        try {
            double balance = bank.get_balance(account_ids[idx]);
            (void)balance; // Read operation - balance used for monitoring
        } catch (const std::exception& e) {
            std::cerr << "Error reading balance: " << e.what() << std::endl;
        }
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
    }
}

int main() {
    SecureBank bank;

    // Create accounts
    std::vector<std::string> account_ids = {"ACC001", "ACC002", "ACC003", "ACC004", "ACC005"};
    double initial_balance = 10000.0;

    for (const auto& id : account_ids) {
        if (!bank.create_account(id, initial_balance)) {
            std::cerr << "Failed to create account: " << id << std::endl;
            return 1;
        }
    }

    std::cout << "Initial state:" << std::endl;
    bank.print_all_balances();

    double total_initial = initial_balance * account_ids.size();
    std::cout << "Total money in system: $" << std::fixed << std::setprecision(2)
              << total_initial << std::endl;

    const int transactions_per_thread = 20;

    std::vector<std::thread> threads;

    // Deposit threads
    for (size_t i = 0; i < account_ids.size(); ++i) {
        threads.emplace_back(deposit_worker, std::ref(bank), account_ids[i], transactions_per_thread);
    }

    // Withdraw threads
    for (size_t i = 0; i < account_ids.size(); ++i) {
        threads.emplace_back(withdraw_worker, std::ref(bank), account_ids[i], transactions_per_thread);
    }

    // Transfer threads
    for (int i = 0; i < 4; ++i) {
        threads.emplace_back(transfer_worker, std::ref(bank), std::cref(account_ids), transactions_per_thread);
    }

    // Reader threads
    for (int i = 0; i < 3; ++i) {
        threads.emplace_back(balance_reader, std::ref(bank), std::cref(account_ids), transactions_per_thread * 2);
    }

    // Wait for all threads to complete
    for (auto& t : threads) {
        if (t.joinable()) {
            t.join();
        }
    }

    std::cout << "\nFinal state:" << std::endl;
    bank.print_all_balances();

    // Verify transfers didn't create or destroy money
    // (deposits and withdrawals will change the total)
    double total_final = 0.0;
    for (const auto& id : account_ids) {
        try {
            total_final += bank.get_balance(id);
        } catch (const std::exception& e) {
            std::cerr << "Error: " << e.what() << std::endl;
        }
    }

    std::cout << "Total money in system: $" << std::fixed << std::setprecision(2)
              << total_final << std::endl;
    std::cout << "Total transactions processed: " << bank.get_transaction_count() << std::endl;

    bank.print_transaction_log();

    return 0;
}